/**
 * Fastify server entry point.
 */

import Fastify from 'fastify';
import cors from '@fastify/cors';
import { projectRoutes } from './routes/projects.js';
import { taskRoutes } from './routes/tasks.js';
import { dependencyRoutes } from './routes/dependencies.js';
import { calendarRoutes } from './routes/calendars.js';
import { resourceRoutes } from './routes/resources.js';
import { assignmentRoutes } from './routes/assignments.js';
import { baselineRoutes } from './routes/baselines.js';
import { importExportRoutes } from './routes/importExport.js';

const server = Fastify({
  logger: true,
});

await server.register(cors, {
  origin: true,
});

// Register route modules
await server.register(projectRoutes, { prefix: '/api' });
await server.register(taskRoutes, { prefix: '/api' });
await server.register(dependencyRoutes, { prefix: '/api' });
await server.register(calendarRoutes, { prefix: '/api' });
await server.register(resourceRoutes, { prefix: '/api' });
await server.register(assignmentRoutes, { prefix: '/api' });
await server.register(baselineRoutes, { prefix: '/api' });
await server.register(importExportRoutes, { prefix: '/api' });

// Health check
server.get('/api/health', async () => ({ status: 'ok' }));

// Global error handler
server.setErrorHandler((error, request, reply) => {
  server.log.error(error);
  reply.status(error.statusCode ?? 500).send({
    error: error.message ?? 'Internal Server Error',
  });
});

const start = async () => {
  try {
    const port = parseInt(process.env.PORT ?? '3001', 10);
    await server.listen({ port, host: '0.0.0.0' });
    server.log.info(`Server running on http://localhost:${port}`);
  } catch (err) {
    server.log.error(err);
    process.exit(1);
  }
};

start();

export { server };
